                padding: "6px 14px",
                fontSize: 13,
                fontWeight: 500,
                border: "none",
                cursor: "pointer",
                transition: "background 150ms ease, color 150ms ease",
              }}
            >
              {METRIC_LABELS[m]}
            </button>
          ))}
        </div>
      </div>
    </section>
  );
}

