    if (!userRequestedClose.current) return;
    userRequestedClose.current = false;
    if (closeFallbackTimer.current) {
      clearTimeout(closeFallbackTimer.current);
      closeFallbackTimer.current = null;
    }
    onClose();
  }

  function onHandleTouchStart(e: React.TouchEvent) {
    dragging.current = true;
    dragStartY.current = e.touches[0].clientY;
  }

  function onHandleTouchMove(e: React.TouchEvent) {
    if (!dragging.current) return;
    const y = e.touches[0].clientY;
    const dy = Math.max(0, y - dragStartY.current);
    setDragY(dy);
  }

  function onHandleTouchEnd() {
    if (!dragging.current) return;
    dragging.current = false;
    if (dragY > 72) {
      requestClose();
    } else {
      setDragY(0);
    }
  }

  if (view === null) return null;

  /* translate3d keeps iOS GPU layers consistent with opaque fills */
  const sheetTransform = entered
    ? `translate3d(0, ${dragY}px, 0)`
    : `translate3d(0, calc(100% + ${dragY}px), 0)`;

  /* Portal to body: avoids iOS/WebKit stacking bugs where fixed UI inside the page
   * tree paints under later siblings (e.g. the feed) and odd backdrop rendering. */
  const overlay = (
    <div
      className="fixed inset-0 flex flex-col justify-end"
      style={{ zIndex: 9999 }}
      role="presentation"
    >
      <button
        type="button"
        aria-label="Close panel"
        className="absolute inset-0 transition-opacity"
        style={{
          zIndex: 0,
          /* Explicit rgba: Tailwind bg-black/45 can look invisible on some mobile WebKit builds. */
          backgroundColor: "rgba(0, 0, 0, 0.52)",
          opacity: entered ? 1 : 0,
          transitionDuration: `${SHEET_MS}ms`,
          transitionTimingFunction: SHEET_EASE,
        }}
        onClick={requestClose}
      />

      <div
        className="relative z-10 mt-auto flex max-h-[min(92dvh,900px)] w-full flex-col overflow-hidden rounded-t-[24px] shadow-[0_-8px_40px_rgba(0,0,0,0.18)] dark:shadow-[0_-8px_40px_rgba(0,0,0,0.45)]"
        style={{
          ...opaqueLayerStyle(shellBg),
          transform: sheetTransform,
          transitionProperty: entered && dragY === 0 ? "transform" : "none",
          transitionDuration: `${SHEET_MS}ms`,
          transitionTimingFunction: SHEET_EASE,
        }}
        onTransitionEnd={handleSheetTransitionEnd}
      >
        <div
          className="flex flex-shrink-0 flex-col items-center px-4 pb-3 pt-2"
          style={{
            ...opaqueLayerStyle(shellBg),
            borderBottom: `1px solid ${hairline}`,
          }}
        >
          <div
            className="mb-2 flex w-full justify-center py-2"
            onTouchStart={onHandleTouchStart}
            onTouchMove={onHandleTouchMove}
            onTouchEnd={onHandleTouchEnd}
            onTouchCancel={onHandleTouchEnd}
          >
            <div
              className="h-1 w-10 shrink-0 rounded-full bg-zinc-300 dark:bg-zinc-600"
              aria-hidden
            />
          </div>
          <div className="flex w-full items-center justify-between gap-3">
            <p
              className="text-[17px] font-bold"
              style={{ color: isDark ? "#f9f9f9" : "#111827" }}
            >
              {VIEW_TITLES[view]}
            </p>
            <button
              type="button"
              aria-label="Close"
              onClick={requestClose}
              className="flex h-10 w-10 items-center justify-center rounded-full text-zinc-500 transition hover:bg-zinc-100 dark:hover:bg-zinc-800"
            >
              <GellogClose size={22} strokeWidth={2} />
            </button>
          </div>
        </div>

        <div
          className="min-h-0 flex-1 overflow-y-auto overscroll-contain px-4 pt-4"
          style={{
            ...opaqueLayerStyle(shellBg),
            paddingBottom: "max(2rem, env(safe-area-inset-bottom, 0px))",
          }}
        >
          {view === "stats" ? (
            <StatsBody stats={stats} cardBg={cardBg} hairline={hairline} isDark={isDark} />
          ) : null}
          {view === "flavours" ? (
            <FlavoursBody
              rankedFlavours={rankedFlavours}
              uncategorisedLogCount={uncategorisedLogCount}
              uncategorisedInputNames={uncategorisedInputNames}
              cardBg={cardBg}
              hairline={hairline}
              isDark={isDark}
            />
          ) : null}
          {view === "calendar" ? (
            <div
              className="p-4"
              style={{
                ...opaqueLayerStyle(cardBg),
                border: `1px solid ${hairline}`,
                borderRadius: 20,
              }}
            >
              <IceCreamHeatmap data={heatmapData} />
            </div>
          ) : null}
        </div>
      </div>
    </div>
  );

  if (typeof document === "undefined") return null;
  return createPortal(overlay, document.body);
}

function StatsBody({
  stats,
  cardBg,
  hairline,
  isDark,
}: {
  stats: ProfileSheetStats;
  cardBg: string;
  hairline: string;
  isDark: boolean;
}) {
  const {
    totalAllTime,
    totalThisYear,
    averageOverallRating,
    mostVisitedSalon,
    bestWeather,
    totalSpent,
    averagePerVisit,
  } = stats;

  const rows: { label: string; value: string }[] = [
    { label: "Total scoops", value: String(totalAllTime) },
    { label: "This year", value: String(totalThisYear) },
    {
      label: "Average rating",
      value: formatAverageRating(averageOverallRating),
    },
    {
      label: "Most visited salon",
      value: mostVisitedSalon
        ? `${mostVisitedSalon.name} (${mostVisitedSalon.count}×)`
        : "—",
    },
    { label: "Best weather", value: bestWeather ?? "—" },
  ];

  if (totalSpent != null) {
    rows.push({ label: "Total spent", value: `€${totalSpent.toFixed(2)}` });
  }
  if (averagePerVisit != null) {
    rows.push({
      label: "Avg per visit",
      value: `€${averagePerVisit.toFixed(2)}`,
    });
  }

  return (
    <div
      className="p-4"
      style={{
        ...opaqueLayerStyle(cardBg),
        border: `1px solid ${hairline}`,
        borderRadius: 20,
      }}
    >
      <div className="grid grid-cols-2 gap-4">
        {rows.map((stat) => (
          <div key={stat.label} className="flex flex-col gap-0.5">
            <p className="text-xs" style={{ color: isDark ? "#aeaeb2" : "#6b7280" }}>
              {stat.label}
            </p>
            <p
              className="truncate text-base font-semibold"
              style={{ color: isDark ? "#f9f9f9" : "#111827" }}
            >
              {stat.value}
            </p>
          </div>
        ))}
      </div>
    </div>
  );
}

function FlavoursBody({
  rankedFlavours,
  uncategorisedLogCount,
  uncategorisedInputNames,
  cardBg,
  hairline,
  isDark,
}: {
  rankedFlavours: ProfileSheetRankedFlavour[];
  uncategorisedLogCount: number;
  uncategorisedInputNames: string[];
  cardBg: string;
  hairline: string;
  isDark: boolean;
}) {
  const [uncExpanded, setUncExpanded] = useState(false);
  const muted = isDark ? "#aeaeb2" : "#6b7280";
  const fg = isDark ? "#f9f9f9" : "#111827";

  return (
    <div
      className="p-4"
      style={{
        ...opaqueLayerStyle(cardBg),
        border: `1px solid ${hairline}`,
        borderRadius: 20,
      }}
    >
      {rankedFlavours.length === 0 ? (
        <p className="text-sm" style={{ color: muted }}>
          Keep logging — resolved flavours show here once they match the flavour
          catalogue.
        </p>
      ) : (
        <ul className="flex flex-col">
          {rankedFlavours.map((flavour) => (
            <li
              key={flavour.flavourId}
              className="flex items-center gap-2 border-t py-2.5 first:border-t-0 first:pt-0 last:pb-0"
              style={{ borderColor: hairline }}
            >
              <div
                className="flex w-7 shrink-0 items-center justify-center text-xs font-bold"
                style={{ color: fg }}
                aria-label={`Rank ${flavour.rank}`}
              >
                #{flavour.rank}
              </div>
              <div className="flex shrink-0 items-center justify-center">
                <Gelato
                  variant="scoop"
                  tokens={flavour.tokens}
                  size={48}
                  seed={flavour.flavourId}
                  className="flex"
                />
              </div>
              <div className="min-w-0 flex-1">
                <span className="block truncate text-sm font-medium" style={{ color: fg }}>
                  {flavour.displayName}
                </span>
              </div>
              <span
                className="shrink-0 tabular-nums text-sm font-medium"
                style={{ color: fg }}
              >
                {flavour.logCount}×
              </span>
              <span
                className="w-11 shrink-0 text-right text-sm font-semibold tabular-nums"
                style={{ color: isDark ? "#fb923c" : "#ea580c" }}
              >
                {flavour.avgRating != null ? `${flavour.avgRating.toFixed(1)} ★` : "—"}
              </span>
            </li>
          ))}
        </ul>
      )}

      {uncategorisedLogCount > 0 ? (
        <div className="mt-3 border-t pt-3" style={{ borderColor: hairline }}>
          <button
            type="button"
            onClick={() => setUncExpanded((v) => !v)}
            className="w-full text-left text-xs font-medium underline-offset-2 hover:underline"
            style={{ color: muted }}
            aria-expanded={uncExpanded}
          >
            {uncategorisedLogCount}{" "}
            {uncategorisedLogCount === 1 ? "log" : "logs"} uncategorised
          </button>
          {uncExpanded ? (
            uncategorisedInputNames.length > 0 ? (
              <ul className="mt-2 flex list-disc flex-col gap-1 pl-5 text-xs" style={{ color: fg }}>
                {uncategorisedInputNames.map((name) => (
                  <li key={name} className="marker:text-zinc-400">
                    {name}
                  </li>
                ))}
              </ul>
            ) : (
              <p className="mt-2 text-xs" style={{ color: muted }}>
                No typed names on file for these entries.
              </p>
            )
          ) : null}
        </div>
      ) : null}
    </div>
  );
}

