// GellogFlavour: a scoop shape — stroke-only circle with a small curved
// wafer/cone line at the bottom
export function GellogFlavour({
  size = 24,
  color = "currentColor",
  strokeWidth = 1.5,
  ...rest
}: {
  size?: number;
  color?: string;
  strokeWidth?: number;
} & Omit<SVGProps<SVGSVGElement>, "width" | "height">) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      stroke={color}
      strokeWidth={strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round"
      aria-hidden="true"
      {...rest}
    >
      {/* Scoop circle */}
      <circle cx="12" cy="9" r="6" />
      {/* Wafer/cone connection — a small curved line at the bottom */}
      <path d="M9 15 Q12 18 15 15" />
    </svg>
  );
}

// GellogGellog: a stylised "G" wordmark letterform in the Gellog brand style
export function GellogGellog({
  size = 24,
  color = "var(--brand-primary)",
  ...rest
}: {
  size?: number;
  color?: string;
} & Omit<SVGProps<SVGSVGElement>, "width" | "height">) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      aria-hidden="true"
      {...rest}
    >
      <text
        x="12"
        y="18"
        textAnchor="middle"
        fontFamily="system-ui, -apple-system, sans-serif"
        fontSize="20"
        fontWeight="700"
        fill={color}
      >
        G
      </text>
    </svg>
  );
}

// ─── Icon registry ─────────────────────────────────────────────────────────────

type StandardIconComponent = FC<LucideProps>;
type CustomIconComponent = FC<{
  size?: number;
  color?: string;
  strokeWidth?: number;
}>;

const ICON_MAP: Record<string, StandardIconComponent | CustomIconComponent> = {
  GellogLog,
  GellogFeed,
  GellogSearch,
  GellogHome,
  GellogProfile,
  GellogSettings,
  GellogShare,
  GellogLike,
  GellogComment,
  GellogFollow,
  GellogSalon,
  GellogWeather,
  GellogStar,
  GellogPhoto,
  GellogBack,
  GellogClose,
  GellogRight,
  GellogCheck,
  GellogTrophy,
  GellogCalendar,
  GellogBookmark,
  GellogData,
  GellogNotification,
  GellogDirections,
  GellogFlavour,
  GellogGellog,
};

export type IconName = keyof typeof ICON_MAP;

// ─── Icon component ───────────────────────────────────────────────────────────

type IconProps = {
  name: IconName;
  size?: number;
  color?: string;
  strokeWidth?: number;
};

export function Icon({ name, size = 20, color = "currentColor", strokeWidth = 1.5 }: IconProps) {
  const Component = ICON_MAP[name];
  if (!Component) return null;
  return <Component size={size} color={color} strokeWidth={strokeWidth} />;
}

// ─── IconButton component ─────────────────────────────────────────────────────

type IconButtonProps = {
  name: IconName;
  onPress: () => void;
  color?: string;
  size?: number;
  label: string;
  strokeWidth?: number;
  style?: React.CSSProperties;
  className?: string;
};

export function IconButton({
  name,
  onPress,
  color = "currentColor",
  size = 24,
  label,
  strokeWidth = 1.5,
  style,
  className,
}: IconButtonProps) {
  return (
    <button
      type="button"
      aria-label={label}
      onClick={onPress}
      className={className}
      style={{
        display: "inline-flex",
        alignItems: "center",
        justifyContent: "center",
        width: 44,
        height: 44,
        background: "none",
        border: "none",
        cursor: "pointer",
        padding: 0,
        borderRadius: "50%",
        color,
        ...style,
      }}
      onMouseDown={(e) => {
        (e.currentTarget as HTMLButtonElement).style.opacity = "0.7";
      }}
      onMouseUp={(e) => {
        (e.currentTarget as HTMLButtonElement).style.opacity = "1";
      }}
      onMouseLeave={(e) => {
        (e.currentTarget as HTMLButtonElement).style.opacity = "1";
      }}
      onTouchStart={(e) => {
        (e.currentTarget as HTMLButtonElement).style.opacity = "0.7";
      }}
      onTouchEnd={(e) => {
        (e.currentTarget as HTMLButtonElement).style.opacity = "1";
      }}
    >
      <Icon name={name} size={size} color={color} strokeWidth={strokeWidth} />
    </button>
  );
}

import { createClient } from "./supabase/client";

export async function requestNotificationPermission(): Promise<NotificationPermission> {
  if (!("Notification" in window)) return "denied";
  if (Notification.permission !== "default") return Notification.permission;
  return Notification.requestPermission();
}

export async function registerServiceWorker(): Promise<ServiceWorkerRegistration> {
  if (!("serviceWorker" in navigator)) {
    throw new Error("Service workers are not supported in this browser.");
  }
  const registration = await navigator.serviceWorker.register("/sw.js");
  await navigator.serviceWorker.ready;
  return registration;
}

export async function subscribeToPush(): Promise<PushSubscription> {
  const registration = await registerServiceWorker();

  const vapidKey = process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY;
  if (!vapidKey) throw new Error("NEXT_PUBLIC_VAPID_PUBLIC_KEY is not set.");

  const existing = await registration.pushManager.getSubscription();
  if (existing) {
    await savePushSubscription(existing);
    return existing;
  }

  const subscription = await registration.pushManager.subscribe({
    userVisibleOnly: true,
    applicationServerKey: urlBase64ToUint8Array(vapidKey),
  });

  await savePushSubscription(subscription);
  return subscription;
}

export async function savePushSubscription(subscription: PushSubscription): Promise<void> {
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) throw new Error("Not authenticated.");

  const json = subscription.toJSON();
  const endpoint = json.endpoint!;
  const p256dh = json.keys?.p256dh!;
  const auth = json.keys?.auth!;

  const { error } = await supabase.from("push_subscriptions").upsert(
    { user_id: user.id, endpoint, p256dh, auth },
    { onConflict: "endpoint" }
  );
  if (error) throw error;
}

export async function deletePushSubscription(): Promise<void> {
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return;

  if ("serviceWorker" in navigator) {
    const registration = await navigator.serviceWorker.getRegistration("/sw.js");
    const sub = await registration?.pushManager.getSubscription();
    if (sub) {
      await sub.unsubscribe();
      await supabase
        .from("push_subscriptions")
        .delete()
        .eq("user_id", user.id)
        .eq("endpoint", sub.endpoint);
    }
  }
}

function urlBase64ToUint8Array(base64String: string): Uint8Array<ArrayBuffer> {
  const padding = "=".repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/-/g, "+").replace(/_/g, "/");
  const rawData = atob(base64);
  const buf = new ArrayBuffer(rawData.length);
  const outputArray = new Uint8Array(buf);
  for (let i = 0; i < rawData.length; i++) {
    outputArray[i] = rawData.charCodeAt(i);
  }
  return outputArray;
}

